/**
 * Immutable currency amount in minor units.
 */
export class CurrencyAmount {
  /** @type {number} */
  #cents;

  /** @type {string} */
  #currency;

  /**
   * @param {number} cents
   * @param {string} currency
   */
  constructor(cents, currency) {
    if (!Number.isInteger(cents)) {
      throw new TypeError('cents must be an integer');
    }
    if (typeof currency !== 'string' || !/^[A-Z]{3}$/.test(currency)) {
      throw new TypeError('currency must be a three-letter code');
    }
    this.#cents = cents;
    this.#currency = currency;
  }

  /** @returns {number} */
  get cents() {
    return this.#cents;
  }

  /** @returns {string} */
  get currency() {
    return this.#currency;
  }

  /**
   * @param {CurrencyAmount} other
   * @returns {CurrencyAmount}
   */
  add(other) {
    if (other.currency !== this.#currency) {
      throw new Error('currency mismatch');
    }
    return new CurrencyAmount(this.#cents + other.cents, this.#currency);
  }
}
